import java.util.List;

public class OrderCleaner {

    public record Order(String id, long expiresAt) {
    }

    public void removeExpired(List<Order> orders, long now) {
        for (Order order : orders) {
            if (order.expiresAt() < now) {
                orders.remove(order);
            }
        }
    }
}
